        } catch (MalformedURLException e) {
            return String.format("{\"error\": \"%s\"}", escapeJson("Invalid URL format: " + e.getMessage()));
        } catch (IOException e) {
            return String.format("{\"error\": \"%s\"}", escapeJson("IO error occurred: " + e.getMessage()));
        } catch (Exception e) {
            return String.format("{\"error\": \"%s\"}", escapeJson("Unexpected error: " + e.getMessage()));
        }
